243→    private func loadUserData() async {
244→        journeyState = .loading
245→
246→        // Check feature flags
247→        if let featureFlags = resolver.resolve(FeatureFlagChecking.self) {
248→            isAiWorkoutEnabled = await featureFlags.isFeatureEnabled(.aiWorkoutGenerationEnabled)
249→        }
250→
251→        // Load user info from UserDefaults or Firebase Auth
252→        await loadUserInfo()
253→
254→        guard let profileRepo = resolver.resolve(UserProfileRepository.self),
255→              let entitlementRepo = resolver.resolve(EntitlementRepository.self) else {
256→            journeyState = .error(message: "Erro de configuração do app.")
257→            handleError(DomainError.repositoryFailure(reason: "Serviços não configurados"))
258→            return
259→        }
260→
261→        do {
262→            // Carregar entitlement (respeitar debug override se ativo)
263→            #if DEBUG
264→            if DebugEntitlementOverride.shared.isEnabled {
265→                entitlement = DebugEntitlementOverride.shared.entitlement
266→            } else {
267→                entitlement = try await entitlementRepo.currentEntitlement()
268→            }
269→            #else
270→            entitlement = try await entitlementRepo.currentEntitlement()
271→            #endif
272→            
273→            let loadedProfile = try await profileRepo.loadProfile()
274→
275→            guard let profile = loadedProfile else {
276→                journeyState = .noProfile
277→                // Carregar programas mesmo sem perfil
278→                await loadProgramsAndWorkouts(profile: nil)
279→                return
280→            }
281→
282→            // Atualizar estado do treino diário
283→            dailyWorkoutState = dailyStateManager.loadTodayState()
284→            
285→            // Verificar se já concluiu/pulou o treino hoje
286→            if dailyWorkoutState.isFinished {
287→                journeyState = .workoutCompleted(profile: profile)
288→                await loadProgramsAndWorkouts(profile: profile)
289→                return
290→            }
291→
292→            journeyState = .workoutReady(profile: profile)
293→
294→            // Carregar programas e treinos recomendados
295→            await loadProgramsAndWorkouts(profile: profile)
296→
297→        } catch {
298→            journeyState = .error(message: "Não foi possível carregar seus dados.")
299→            handleError(error) // ErrorPresenting protocol
300→        }
301→    }
