303→    private func loadProgramsAndWorkouts(profile: UserProfile?) async {
304→        let recommender = ProgramRecommender()
305→
306→        // Carregar histórico para recomendação e stats
307→        if let historyRepo = resolver.resolve(WorkoutHistoryRepository.self) {
308→            do {
309→                historyEntries = try await historyRepo.listEntries()
310→            } catch {
311→                historyEntries = []
312→                #if DEBUG
313→                print("[Home] Erro ao carregar histórico: \(error)")
314→                #endif
315→            }
316→        }
317→
318→        // Carregar programas "Top for You" (até 4) usando o recomendador
319→        if let programRepo = resolver.resolve(ProgramRepository.self) {
320→            do {
321→                let allPrograms = try await programRepo.listPrograms()
322→                topPrograms = recommender.recommend(
323→                    programs: allPrograms,
324→                    profile: profile,
325→                    history: historyEntries,
326→                    limit: 4
327→                )
328→            } catch {
329→                #if DEBUG
330→                print("[Home] Erro ao carregar programas: \(error)")
331→                #endif
332→            }
333→        }
334→
335→        // Load today's workout from the best recommended program
336→        await loadTodayWorkout()
337→    }
