420→                        .buttonStyle(.borderedProminent)
421→                        .tint(FitTodayColor.brandPrimary)
422→                    }
423→                    .padding(FitTodaySpacing.xl)
424→                } else if let pdfURL = localURL {
425→                    PDFKitView(url: pdfURL)
426→                        .ignoresSafeArea(edges: .bottom)
427→                }
428→            }
429→            .navigationTitle(title)
430→            .navigationBarTitleDisplayMode(.inline)
431→            .toolbar {
432→                ToolbarItem(placement: .topBarTrailing) {
433→                    Button("common.done".localized) {
434→                        dismiss()
435→                    }
436→                }
437→                if let pdfURL = localURL {
438→                    ToolbarItem(placement: .topBarLeading) {
