 12→/// Estado da jornada do usuário na Home.
 13→enum HomeJourneyState: Equatable {
 14→    /// Carregando dados iniciais.
 15→    case loading
 16→    /// Usuário não possui perfil → deve ir para onboarding/setup.
 17→    case noProfile
 18→    /// Perfil carregado, treino pronto para gerar via IA.
 19→    case workoutReady(profile: UserProfile)
 20→    /// Treino concluído/pulado hoje - aguardar próximo dia.
 21→    case workoutCompleted(profile: UserProfile)
 22→    /// Erro ao carregar dados.
 23→    case error(message: String)
 24→}
