100→    var workoutsThisWeek: Int {
101→        let calendar = Calendar.current
102→        let now = Date()
103→        guard let weekStart = calendar.date(from: calendar.dateComponents([.yearForWeekOfYear, .weekOfYear], from: now)) else {
104→            return 0
105→        }
106→        return historyEntries.filter { $0.date >= weekStart }.count
107→    }
108→
109→    var caloriesBurnedFormatted: String {
110→        let calendar = Calendar.current
111→        let now = Date()
112→        guard let weekStart = calendar.date(from: calendar.dateComponents([.yearForWeekOfYear, .weekOfYear], from: now)) else {
113→            return "0"
114→        }
115→        let weekCalories = historyEntries
116→            .filter { $0.date >= weekStart }
117→            .reduce(0) { $0 + ($1.caloriesBurned ?? 0) }
118→
119→        if weekCalories >= 1000 {
120→            return String(format: "%.1fk", Double(weekCalories) / 1000.0)
121→        }
122→        return "\(weekCalories)"
123→    }
124→
125→    var streakDays: Int {
126→        guard !historyEntries.isEmpty else { return 0 }
127→
128→        let calendar = Calendar.current
129→        let sortedDates = historyEntries
130→            .map { calendar.startOfDay(for: $0.date) }
131→            .sorted(by: >)
132→
133→        guard let mostRecent = sortedDates.first else { return 0 }
134→
135→        // Check if streak is still active (workout today or yesterday)
136→        let today = calendar.startOfDay(for: Date())
137→        let yesterday = calendar.date(byAdding: .day, value: -1, to: today)!
138→
139→        guard mostRecent >= yesterday else { return 0 }
140→
141→        var streak = 1
142→        var currentDate = mostRecent
143→
144→        for date in sortedDates.dropFirst() {
145→            let expectedPrevious = calendar.date(byAdding: .day, value: -1, to: currentDate)!
146→            if date == expectedPrevious {
147→                streak += 1
148→                currentDate = date
149→            } else if date == currentDate {
150→                // Same day, skip
151→                continue
152→            } else {
153→                break
154→            }
155→        }
156→
157→        return streak
158→    }
159→
160→    /// Days of the week with completed workouts (0=Sunday, 6=Saturday)
161→    var weekCompletedDays: Set<Int> {
162→        let calendar = Calendar.current
163→        let now = Date()
164→        guard let weekStart = calendar.date(from: calendar.dateComponents([.yearForWeekOfYear, .weekOfYear], from: now)) else {
165→            return []
166→        }
167→        var days = Set<Int>()
168→        for entry in historyEntries where entry.date >= weekStart {
169→            let weekday = calendar.component(.weekday, from: entry.date) - 1 // 0=Sunday
170→            days.insert(weekday)
171→        }
172→        return days
173→    }
174→
175→    var weeklyTarget: Int {
176→        userProfile?.weeklyFrequency ?? 4
177→    }
178→
