180→        let calendar = Calendar.current
181→        let now = Date()
182→        guard let weekStart = calendar.date(from: calendar.dateComponents([.yearForWeekOfYear, .weekOfYear], from: now)) else {
183→            return 0
184→        }
185→        return historyEntries
186→            .filter { $0.date >= weekStart }
187→            .reduce(0) { $0 + ($1.completedExercises?.count ?? 0) }
188→    }
189→
190→    var avgDurationMinutes: Int {
191→        let calendar = Calendar.current
192→        let now = Date()
193→        guard let weekStart = calendar.date(from: calendar.dateComponents([.yearForWeekOfYear, .weekOfYear], from: now)) else {
194→            return 0
195→        }
196→        let weekEntries = historyEntries.filter { $0.date >= weekStart }
197→        guard !weekEntries.isEmpty else { return 0 }
198→        let totalMinutes = weekEntries.reduce(0) { $0 + ($1.durationMinutes ?? 0) }
199→        return totalMinutes / weekEntries.count
200→    }
201→
202→    var ctaTitle: String {
203→        switch journeyState {
204→        case .loading:
205→            return "home.cta.loading".localized
206→        case .noProfile:
207→            return "home.cta.setup_profile".localized
208→        case .workoutReady:
209→            return "home.cta.view_today_workout".localized
210→        case .workoutCompleted:
211→            return "home.cta.next_workout_soon".localized
212→        case .error:
