217→    var ctaSubtitle: String? {
218→        switch journeyState {
219→        case .workoutReady:
220→            if canSwapSuggestion {
221→                return "home.cta.subtitle.swap".localized
222→            }
223→            return "home.cta.subtitle.workout_ready".localized
224→        case .workoutCompleted:
225→            return "home.cta.subtitle.completed".localized
226→        default:
227→            return nil
228→        }
229→    }
