243→    private func loadUserData() async {
244→        journeyState = .loading
245→
246→        // Check feature flags
247→        if let featureFlags = resolver.resolve(FeatureFlagChecking.self) {
248→            isAiWorkoutEnabled = await featureFlags.isFeatureEnabled(.aiWorkoutGenerationEnabled)
249→        }
250→
251→        // Load user info from UserDefaults or Firebase Auth
252→        await loadUserInfo()
253→
254→        guard let profileRepo = resolver.resolve(UserProfileRepository.self),
255→              let entitlementRepo = resolver.resolve(EntitlementRepository.self) else {
256→            journeyState = .error(message: "Erro de configuração do app.")
257→            handleError(DomainError.repositoryFailure(reason: "Serviços não configurados"))
258→            return
259→        }
260→
261→        do {
262→            // Carregar entitlement (respeitar debug override se ativo)
263→            #if DEBUG
264→            if DebugEntitlementOverride.shared.isEnabled {
265→                entitlement = DebugEntitlementOverride.shared.entitlement
266→            } else {
267→                entitlement = try await entitlementRepo.currentEntitlement()
268→            }
269→            #else
270→            entitlement = try await entitlementRepo.currentEntitlement()
271→            #endif
272→            
273→            let loadedProfile = try await profileRepo.loadProfile()
274→
275→            guard let profile = loadedProfile else {
276→                journeyState = .noProfile
277→                // Carregar programas mesmo sem perfil
278→                await loadProgramsAndWorkouts(profile: nil)
279→                return
280→            }
281→
282→            // Atualizar estado do treino diário
283→            dailyWorkoutState = dailyStateManager.loadTodayState()
284→            
285→            // Verificar se já concluiu/pulou o treino hoje
286→            if dailyWorkoutState.isFinished {
287→                journeyState = .workoutCompleted(profile: profile)
288→                await loadProgramsAndWorkouts(profile: profile)
289→                return
290→            }
291→
292→            journeyState = .workoutReady(profile: profile)
293→
294→            // Carregar programas e treinos recomendados
295→            await loadProgramsAndWorkouts(profile: profile)
296→
297→        } catch {
298→            journeyState = .error(message: "Não foi possível carregar seus dados.")
299→            handleError(error) // ErrorPresenting protocol
300→        }
301→    }
302→
303→    private func loadProgramsAndWorkouts(profile: UserProfile?) async {
304→        let recommender = ProgramRecommender()
305→
306→        // Carregar histórico para recomendação e stats
307→        if let historyRepo = resolver.resolve(WorkoutHistoryRepository.self) {
308→            do {
309→                historyEntries = try await historyRepo.listEntries()
310→            } catch {
311→                historyEntries = []
312→                #if DEBUG
313→                print("[Home] Erro ao carregar histórico: \(error)")
314→                #endif
315→            }
316→        }
317→
318→        // Carregar programas "Top for You" (até 4) usando o recomendador
319→        if let programRepo = resolver.resolve(ProgramRepository.self) {
320→            do {
321→                let allPrograms = try await programRepo.listPrograms()
322→                topPrograms = recommender.recommend(
323→                    programs: allPrograms,
324→                    profile: profile,
325→                    history: historyEntries,
326→                    limit: 4
327→                )
328→            } catch {
329→                #if DEBUG
330→                print("[Home] Erro ao carregar programas: \(error)")
331→                #endif
332→            }
333→        }
334→
335→        // Load today's workout from the best recommended program
336→        await loadTodayWorkout()
337→    }
338→
339→    private func loadTodayWorkout() async {
340→        guard let bestProgram = topPrograms.first else { return }
341→
342→        todayProgramName = bestProgram.shortName
343→
344→        guard let programRepo = resolver.resolve(ProgramRepository.self),
345→              let workoutRepo = resolver.resolve(WgerProgramWorkoutRepository.self) else {
346→            return
347→        }
348→
349→        let useCase = LoadProgramWorkoutsUseCase(
350→            programRepository: programRepo,
351→            workoutRepository: workoutRepo
352→        )
353→
354→        isLoadingWorkout = true
355→        defer { isLoadingWorkout = false }
356→
357→        do {
358→            let workouts = try await useCase.execute(programId: bestProgram.id)
359→            if !workouts.isEmpty {
360→                let index = workoutsThisWeek % workouts.count
361→                todayWorkout = workouts[index]
362→            }
363→        } catch {
364→            #if DEBUG
365→            print("[Home] Erro ao carregar treino do dia: \(error)")
366→            #endif
367→        }
368→    }
