507→    /// Observar mudanças no entitlement em background.
508→    func startObservingEntitlement() {
509→        Task {
510→            guard let repo = resolver.resolve(EntitlementRepository.self) else { return }
511→            for await newEntitlement in repo.entitlementStream() {
512→                self.entitlement = newEntitlement
513→            }
514→        }
515→    }
516→}
