 84→// MARK: - Request Trainer Connection Use Case
 85→
 86→protocol RequestTrainerConnectionUseCaseProtocol: Sendable {
 87→    func execute(trainerId: String) async throws -> String
 88→}
 89→
 90→final class RequestTrainerConnectionUseCase: RequestTrainerConnectionUseCaseProtocol, @unchecked Sendable {
 91→    private let trainerStudentRepository: TrainerStudentRepository
 92→    private let authRepository: AuthenticationRepository
 93→    private let featureFlagChecker: FeatureFlagChecking
 94→
 95→    init(
 96→        trainerStudentRepository: TrainerStudentRepository,
 97→        authRepository: AuthenticationRepository,
 98→        featureFlagChecker: FeatureFlagChecking
 99→    ) {
100→        self.trainerStudentRepository = trainerStudentRepository
101→        self.authRepository = authRepository
102→        self.featureFlagChecker = featureFlagChecker
103→    }
104→
105→    func execute(trainerId: String) async throws -> String {
106→        guard await featureFlagChecker.isFeatureEnabled(.personalTrainerEnabled) else {
107→            throw PersonalTrainerError.featureDisabled
108→        }
109→
110→        guard let currentUser = try await authRepository.currentUser() else {
111→            throw PersonalTrainerError.unauthorized
112→        }
113→
114→        // Check if already has an active connection
115→        if let existingRelationship = try await trainerStudentRepository.getCurrentRelationship(studentId: currentUser.id) {
116→            if existingRelationship.status == .active || existingRelationship.status == .pending {
117→                throw PersonalTrainerError.alreadyConnected
118→            }
119→        }
120→
121→        let relationshipId = try await trainerStudentRepository.requestConnection(
122→            trainerId: trainerId,
123→            studentId: currentUser.id,
124→            studentDisplayName: currentUser.displayName
125→        )
126→
127→        return relationshipId
128→    }
129→}
