131→// MARK: - Cancel Trainer Connection Use Case
132→
133→protocol CancelTrainerConnectionUseCaseProtocol: Sendable {
134→    func execute(relationshipId: String) async throws
135→}
136→
137→final class CancelTrainerConnectionUseCase: CancelTrainerConnectionUseCaseProtocol, @unchecked Sendable {
138→    private let trainerStudentRepository: TrainerStudentRepository
139→    private let authRepository: AuthenticationRepository
140→    private let featureFlagChecker: FeatureFlagChecking
141→
142→    init(
143→        trainerStudentRepository: TrainerStudentRepository,
144→        authRepository: AuthenticationRepository,
145→        featureFlagChecker: FeatureFlagChecking
146→    ) {
147→        self.trainerStudentRepository = trainerStudentRepository
148→        self.authRepository = authRepository
149→        self.featureFlagChecker = featureFlagChecker
150→    }
151→
152→    func execute(relationshipId: String) async throws {
153→        guard await featureFlagChecker.isFeatureEnabled(.personalTrainerEnabled) else {
154→            throw PersonalTrainerError.featureDisabled
155→        }
156→
157→        guard try await authRepository.currentUser() != nil else {
158→            throw PersonalTrainerError.unauthorized
159→        }
160→
161→        try await trainerStudentRepository.cancelConnection(relationshipId: relationshipId)
162→    }
163→}
