172→final class GetCurrentTrainerUseCase: GetCurrentTrainerUseCaseProtocol, @unchecked Sendable {
173→    private let trainerRepository: PersonalTrainerRepository
174→    private let trainerStudentRepository: TrainerStudentRepository
175→    private let authRepository: AuthenticationRepository
176→    private let featureFlagChecker: FeatureFlagChecking
177→
178→    init(
179→        trainerRepository: PersonalTrainerRepository,
180→        trainerStudentRepository: TrainerStudentRepository,
181→        authRepository: AuthenticationRepository,
182→        featureFlagChecker: FeatureFlagChecking
183→    ) {
184→        self.trainerRepository = trainerRepository
185→        self.trainerStudentRepository = trainerStudentRepository
186→        self.authRepository = authRepository
187→        self.featureFlagChecker = featureFlagChecker
188→    }
189→
190→    func execute() async throws -> (trainer: PersonalTrainer, relationship: TrainerStudentRelationship)? {
191→        guard await featureFlagChecker.isFeatureEnabled(.personalTrainerEnabled) else {
192→            return nil
193→        }
194→
195→        guard let currentUser = try await authRepository.currentUser() else {
196→            return nil
197→        }
198→
199→        guard let relationship = try await trainerStudentRepository.getCurrentRelationship(studentId: currentUser.id) else {
200→            return nil
201→        }
202→
203→        guard relationship.status == .active || relationship.status == .pending else {
204→            return nil
205→        }
206→
207→        guard let trainer = try? await trainerRepository.fetchTrainer(id: relationship.trainerId) else {
208→            return nil
209→        }
210→
211→        return (trainer, relationship)
212→    }
213→
214→    func observeRelationship() -> AsyncStream<TrainerStudentRelationship?> {
215→        AsyncStream { continuation in
216→            Task {
217→                guard await featureFlagChecker.isFeatureEnabled(.personalTrainerEnabled) else {
218→                    continuation.yield(nil)
219→                    continuation.finish()
220→                    return
221→                }
222→
223→                guard let currentUser = try? await authRepository.currentUser() else {
224→                    continuation.yield(nil)
225→                    continuation.finish()
226→                    return
227→                }
228→
229→                for await relationship in trainerStudentRepository.observeRelationship(studentId: currentUser.id) {
230→                    continuation.yield(relationship)
231→                }
232→
233→                continuation.finish()
234→            }
235→        }
236→    }
237→}
