239→// MARK: - Fetch Assigned Workouts Use Case
240→
241→protocol FetchAssignedWorkoutsUseCaseProtocol: Sendable {
242→    func execute() async throws -> [TrainerWorkout]
243→    func observe() -> AsyncStream<[TrainerWorkout]>
244→}
245→
246→final class FetchAssignedWorkoutsUseCase: FetchAssignedWorkoutsUseCaseProtocol, @unchecked Sendable {
247→    private let trainerWorkoutRepository: TrainerWorkoutRepository
248→    private let authRepository: AuthenticationRepository
249→    private let featureFlagChecker: FeatureFlagChecking
250→
251→    init(
252→        trainerWorkoutRepository: TrainerWorkoutRepository,
253→        authRepository: AuthenticationRepository,
254→        featureFlagChecker: FeatureFlagChecking
255→    ) {
256→        self.trainerWorkoutRepository = trainerWorkoutRepository
257→        self.authRepository = authRepository
258→        self.featureFlagChecker = featureFlagChecker
259→    }
260→
261→    func execute() async throws -> [TrainerWorkout] {
262→        guard await featureFlagChecker.isFeatureEnabled(.cmsWorkoutSyncEnabled) else {
263→            return []
264→        }
265→
266→        guard let currentUser = try await authRepository.currentUser() else {
267→            return []
268→        }
269→
270→        return try await trainerWorkoutRepository.fetchAssignedWorkouts(studentId: currentUser.id)
271→    }
272→
273→    func observe() -> AsyncStream<[TrainerWorkout]> {
274→        AsyncStream { continuation in
275→            Task {
276→                guard await featureFlagChecker.isFeatureEnabled(.cmsWorkoutSyncEnabled) else {
277→                    continuation.yield([])
278→                    continuation.finish()
279→                    return
280→                }
281→
282→                guard let currentUser = try? await authRepository.currentUser() else {
283→                    continuation.yield([])
284→                    continuation.finish()
285→                    return
286→                }
287→
288→                for await workouts in trainerWorkoutRepository.observeAssignedWorkouts(studentId: currentUser.id) {
289→                    continuation.yield(workouts)
290→                }
291→
292→                continuation.finish()
293→            }
294→        }
295→    }
296→}
