285→private final class InMemoryProfileRepository: UserProfileRepository, @unchecked Sendable {
286→    private var profile: UserProfile?
287→    func loadProfile() async throws -> UserProfile? { profile }
288→    func saveProfile(_ profile: UserProfile) async throws { self.profile = profile }
289→}
290→
291→private final class InMemoryEntitlementRepository: EntitlementRepository, @unchecked Sendable {
292→    func currentEntitlement() async throws -> ProEntitlement { .free }
293→    func entitlementStream() -> AsyncStream<ProEntitlement> {
294→        AsyncStream { continuation in continuation.finish() }
295→    }
296→}
