298→private final class InMemoryHistoryRepository: WorkoutHistoryRepository {
299→    private var entries: [WorkoutHistoryEntry] = []
300→
301→    func listEntries() async throws -> [WorkoutHistoryEntry] {
302→        entries.sorted { $0.date > $1.date }
303→    }
304→    
305→    func listEntries(limit: Int, offset: Int) async throws -> [WorkoutHistoryEntry] {
306→        let sorted = entries.sorted { $0.date > $1.date }
307→        let start = min(offset, sorted.count)
308→        let end = min(offset + limit, sorted.count)
309→        return Array(sorted[start..<end])
310→    }
311→    
312→    func count() async throws -> Int {
313→        entries.count
314→    }
315→
316→    func saveEntry(_ entry: WorkoutHistoryEntry) async throws {
317→        entries.append(entry)
318→    }
319→
320→    func listAppEntriesWithPlan(limit: Int) async throws -> [WorkoutHistoryEntry] {
321→        let filtered = entries
322→            .filter { $0.source == .app && $0.workoutPlan != nil }
323→            .sorted { $0.date > $1.date }
324→        return Array(filtered.prefix(limit))
325→    }
326→}
