  3→  match /databases/{database}/documents {
  4→
  5→    // Helper function to check if user is authenticated
  6→    function isAuthenticated() {
  7→      return request.auth != null;
  8→    }
  9→
 10→    // Helper function to check if user is a member of a group
 11→    function isMemberOfGroup(groupId) {
 12→      return exists(/databases/$(database)/documents/groups/$(groupId)/members/$(request.auth.uid));
 13→    }
 14→
 15→    // Helper function to check if user is admin of a group
 16→    function isAdminOfGroup(groupId) {
 17→      let memberDoc = get(/databases/$(database)/documents/groups/$(groupId)/members/$(request.auth.uid));
 18→      return memberDoc.data.role == 'admin';
 19→    }
 20→
 21→    // Users collection - users can read and write their own document
 22→    match /users/{userId} {
 23→      allow read: if isAuthenticated() && request.auth.uid == userId;
 24→      allow write: if isAuthenticated() && request.auth.uid == userId;
 25→    }
 26→
 27→    // Groups collection
 28→    match /groups/{groupId} {
 29→      // Anyone authenticated can create a group
 30→      allow create: if isAuthenticated();
 31→
 32→      // Only members can read group data
 33→      allow read: if isAuthenticated() && isMemberOfGroup(groupId);
 34→
 35→      // Only admins can update or delete groups
 36→      allow update, delete: if isAuthenticated() && isAdminOfGroup(groupId);
 37→
 38→      // Members subcollection
 39→      match /members/{userId} {
 40→        // Any member of the group can read members
 41→        allow read: if isAuthenticated() && isMemberOfGroup(groupId);
 42→
 43→        // Users can write their own member document (for joining)
 44→        // Or admins can write any member document (for managing members)
 45→        allow write: if isAuthenticated() &&
 46→                       (request.auth.uid == userId || isAdminOfGroup(groupId));
 47→      }
 48→    }
 49→
 50→    // Challenges collection
 51→    match /challenges/{challengeId} {
 52→      // Any authenticated user can read challenges
 53→      allow read: if isAuthenticated();
 54→
 55→      // Only authenticated users can create challenges (usually done by system/cloud functions)
 56→      allow create: if isAuthenticated();
 57→
 58→      // Challenge entries subcollection
 59→      match /entries/{userId} {
 60→        // Any authenticated user can read entries
 61→        allow read: if isAuthenticated();
 62→
 63→        // Users can only write their own entries
 64→        allow write: if isAuthenticated() && request.auth.uid == userId;
 65→      }
 66→    }
 67→
 68→    // Notifications collection
 69→    match /notifications/{notificationId} {
 70→      // Users can only read their own notifications
 71→      allow read: if isAuthenticated() &&
 72→                    resource.data.userId == request.auth.uid;
 73→
 74→      // Any authenticated user can create notifications
 75→      allow create: if isAuthenticated();
 76→
 77→      // Users can update their own notifications (mark as read)
 78→      allow update: if isAuthenticated() &&
 79→                      resource.data.userId == request.auth.uid;
 80→    }
 81→
 82→    // Personal Workouts collection - treinos enviados pelo Personal Trainer
 83→    match /personalWorkouts/{workoutId} {
 84→      // get: single document read — can check resource.data
 85→      allow get: if isAuthenticated() &&
 86→                    resource.data.userId == request.auth.uid;
 87→
 88→      // list: collection query — requires query filter on userId
 89→      allow list: if isAuthenticated() &&
 90→                     request.query.limit <= 50 &&
 91→                     request.auth.uid != null;
 92→
 93→      // Only trainers can create workouts (via CMS/Admin)
 94→      allow create: if false;
 95→
